/**
 * Official Type definitions for the LemonadeJS plugins
 * https://lemonadejs.net
 * Definitions: https://github.com/DefinitelyTyped/DefinitelyTyped
 */
import React from 'react';
import Timeline from './index';

declare namespace TimelineReact {
    /**
     * React-idiomatic camelCase aliases for the lemonadejs callbacks. The
     * wrapper drops the leading `self` argument before invoking these — the
     * instance is available via the forwarded ref.
     *
     * The lowercase names from `Timeline.Options` (e.g. `onupdate`) still
     * work for legacy compatibility, but new code should prefer these.
     */
    interface ReactCallbacks {
        /** Fired after `result` is recomputed (initial render + every change). */
        onUpdate?: (result: Timeline.Item[]) => void;
        /** Fired when the edit icon is clicked on an `editable` item. */
        onEdition?: (entry: Timeline.Item) => void;
    }

    /** Wrapper-only props (the wrapping `<div>` accepts these). */
    interface DOMProps {
        className?: string;
        style?: React.CSSProperties;
        children?: React.ReactNode;
    }
}

declare const TimelineReact: React.MemoExoticComponent<
    React.ForwardRefExoticComponent<
        Omit<Timeline.Options, 'onupdate' | 'onedition'>
        & TimelineReact.ReactCallbacks
        & TimelineReact.DOMProps
        & React.RefAttributes<Timeline.Instance>
    >
>;

export default TimelineReact;
